 40	    IoK8sApiNetworkingV1NetworkPolicy[]
 41	  >({
 42	    groupVersionKind: modelToGroupVersionKind(NetworkPolicyModel),
 43	    isList: true,
 44	    namespace,
 45	  });
 46	
 47	  const { onPaginationChange, pagination } = usePagination();
 48	  const [data, filteredData, onFilterChange] = useListPageFilter(networkPolicies);
 49	  const [columns, activeColumns] = useNetworkPolicyColumn(pagination, data);
 50	  const title = t('NetworkPolicies');
 51	
 52	  return (
 53	    <ListEmptyState<IoK8sApiNetworkingV1NetworkPolicy>
 54	      createButtonlink={SHARED_DEFAULT_PATH_NEW_RESOURCE_FORM}
 55	      data={data}
 56	      kind={NetworkPolicyModel.kind}
 57	      learnMoreLink="https://kubernetes.io/docs/concepts/services-networking/network-policies/"
 58	      loaded={loaded}
 59	      title={title}
 60	    >
 61	      <ListPageHeader title={t('NetworkPolicies')}>
 62	        {!isEmpty(data.length) && (
 63	          <ListPageCreateButton
 64	            className="list-page-create-button-margin"
 65	            createAccessReview={{
 66	              groupVersionKind: modelToGroupVersionKind(NetworkPolicyModel),
 67	              namespace,
 68	            }}
