 70	              navigate(
 71	                `${resourcePathFromModel(
 72	                  NetworkPolicyModel,
 73	                  null,
 74	                  namespace || DEFAULT_NAMESPACE,
 75	                )}/${SHARED_DEFAULT_PATH_NEW_RESOURCE_FORM}`,
 76	              )
 77	            }
 78	          >
 79	            {t('Create NetworkPolicy')}
