 87	              columns: columns?.map(({ additional, id, title: columnTitle }) => ({
 88	                additional,
 89	                id,
 90	                title: columnTitle,
 91	              })),
 92	              id: NetworkPolicyModel.kind,
 93	              selectedColumns: new Set(activeColumns?.map((col) => col?.id)),
