 96	            data={data}
 97	            loaded={loaded}
 98	            onFilterChange={(...args) => {
 99	              onFilterChange(...args);
100	              onPaginationChange({
101	                endIndex: pagination?.perPage,
102	                page: 1,
103	                perPage: pagination?.perPage,
104	                startIndex: 0,
105	              });
106	            }}
107	          />
108	          {loaded && !isEmpty(data.length) && (
109	            <Pagination
110	              isLastFullPageShown
111	              itemCount={data.length}
112	              onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
113	                onPaginationChange({ endIndex, page, perPage, startIndex })
114	              }
115	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
116	                onPaginationChange({ endIndex, page, perPage, startIndex })
117	              }
118	              page={pagination?.page}
119	              perPage={pagination?.perPage}
120	              perPageOptions={paginationDefaultValues}
121	            />
122	          )}
123	        </div>
124	        <VirtualizedTable<IoK8sApiNetworkingV1NetworkPolicy>
125	          columns={activeColumns}
126	          data={filteredData}
127	          loaded={loaded}
128	          loadError={loadError}
129	          NoDataEmptyMsg={NetworkPolicyEmptyState}
130	          Row={NetworkPolicyRow}
131	          unfilteredData={data}
132	        />
133	      </ListPageBody>
134	    </ListEmptyState>
135	  );
136	};
137	
